protocol Networking {
  func data(for request: URLRequest) async throws -> (Data, URLResponse)
}
extension URLSession: Networking {}

struct Endpoint<Response: Decodable> {
  let path: String
  let method: String
  let query: [URLQueryItem]
  let body: Data?
  init(path: String, method: String = "GET", query: [URLQueryItem] = [], body: Data? = nil) {
    self.path = path; self.method = method; self.query = query; self.body = body
  }
}

enum APIError: Error {
  case network(URLError)
  case status(Int, Data)
  case decoding(Error)
}

final class APIClient {
  let baseURL: URL
  let session: Networking
  var authToken: String?
  init(baseURL: URL, session: Networking = URLSession.shared) {
    self.baseURL = baseURL; self.session = session
  }

  func send<R>(_ endpoint: Endpoint<R>) async throws -> R {
    var comp = URLComponents(url: baseURL.appendingPathComponent(endpoint.path), resolvingAgainstBaseURL: false)!
    if !endpoint.query.isEmpty { comp.queryItems = endpoint.query }
    var req = URLRequest(url: comp.url!)
    req.httpMethod = endpoint.method
    req.httpBody = endpoint.body
    req.setValue("application/json", forHTTPHeaderField: "Content-Type")
    if let token = authToken { req.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization") }

    do {
      let (data, resp) = try await session.data(for: req)
      let code = (resp as? HTTPURLResponse)?.statusCode ?? -1
      guard (200..<300).contains(code) else { throw APIError.status(code, data) }
      do { return try JSONDecoder().decode(R.self, from: data) }
      catch { throw APIError.decoding(error) }
    } catch let e as URLError { throw APIError.network(e) }
  }
}

