actor TokenStore {
  private var refreshTask: Task<String, Error>?
  private(set) var accessToken: String?
  let refresh: () async throws -> String
  init(refresh: @escaping () async throws -> String) { self.refresh = refresh }

  // Multiple callers waiting on a refresh share one Task
  func refreshAccessToken() async throws -> String {
    if let task = refreshTask { return try await task.value }
    let task = Task {
      defer { Task { await self.clearTask() } }
      let new = try await refresh()
      self.accessToken = new
      return new
    }
    self.refreshTask = task
    return try await task.value
  }
  private func clearTask() { refreshTask = nil }
}

final class AuthorizedClient {
  let session: URLSession = .shared
  let tokens: TokenStore
  init(tokens: TokenStore) { self.tokens = tokens }

  func send(_ req: URLRequest, retry: Bool = true) async throws -> (Data, HTTPURLResponse) {
    var req = req
    if let token = await tokens.accessToken {
      req.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
    }
    let (data, resp) = try await session.data(for: req)
    let http = resp as! HTTPURLResponse
    if http.statusCode == 401 && retry {
      _ = try await tokens.refreshAccessToken()
      return try await send(req, retry: false)  // single retry — avoids loops
    }
    return (data, http)
  }
}

func uploadAvatar(_ image: Data, name: String) async throws -> Data {
  let boundary = "Boundary-\(UUID().uuidString)"
  var body = Data()
  func append(_ s: String) { body.append(s.data(using: .utf8)!) }

  // Form field: name
  append("--\(boundary)\r\n")
  append("Content-Disposition: form-data; name=\"name\"\r\n\r\n")
  append("\(name)\r\n")

  // File field
  append("--\(boundary)\r\n")
  append("Content-Disposition: form-data; name=\"avatar\"; filename=\"a.jpg\"\r\n")
  append("Content-Type: image/jpeg\r\n\r\n")
  body.append(image)
  append("\r\n--\(boundary)--\r\n")

  var req = URLRequest(url: URL(string: "https://api/upload")!)
  req.httpMethod = "POST"
  req.setValue("multipart/form-data; boundary=\(boundary)", forHTTPHeaderField: "Content-Type")

  let (data, resp) = try await URLSession.shared.upload(for: req, from: body)
  guard let http = resp as? HTTPURLResponse, http.statusCode < 300 else {
    throw URLError(.badServerResponse)
  }
  return data
}

