// 2) Manual pinning via URLSessionDelegate
final class PinnedDelegate: NSObject, URLSessionDelegate {
  let pinnedHashes: Set<Data>
  init(pinnedHashes: Set<Data>) { self.pinnedHashes = pinnedHashes }

  func urlSession(_ session: URLSession,
                  didReceive challenge: URLAuthenticationChallenge,
                  completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void) {
    guard
      challenge.protectionSpace.authenticationMethod == NSURLAuthenticationMethodServerTrust,
      let trust = challenge.protectionSpace.serverTrust
    else { return completionHandler(.cancelAuthenticationChallenge, nil) }

    var error: CFError?
    guard SecTrustEvaluateWithError(trust, &error) else {
      return completionHandler(.cancelAuthenticationChallenge, nil)
    }
    if let chain = SecTrustCopyCertificateChain(trust) as? [SecCertificate] {
      for cert in chain {
        let data = SecCertificateCopyData(cert) as Data
        if pinnedHashes.contains(SHA256.hash(data: data).asData) {
          return completionHandler(.useCredential, URLCredential(trust: trust))
        }
      }
    }
    completionHandler(.cancelAuthenticationChallenge, nil)
  }
}

